module adder_pipe_64bit
(
    input clk,
    input rst_n,
    input i_en,
    input [63:0] adda,
    input [63:0] addb,
    output [64:0] result,
    output o_en
);
    // ADD YOUR CODE BELOW THIS LINE
    // Parameters
    parameter PIPELINE_STAGES = 3;
    // Registers
    reg [63:0] reg_adda[PIPELINE_STAGES-1:0];
    reg [63:0] reg_addb[PIPELINE_STAGES-1:0];
    reg [64:0] reg_result[PIPELINE_STAGES-1:0];
    reg [64:0] reg_carry[PIPELINE_STAGES-1:0];
    reg [2:0] reg_i_en;
    // Wire
    wire [63:0] sum;
    wire [64:0] carry;
    // Wire Assignments
    assign sum[0] = adda[0] ^ addb[0] ^ reg_carry[0];
    assign reg_i_en[0] = i_en;
    assign reg_result[0] = sum[63:0];
    assign reg_carry[0] = carry[63:0];
    assign carry[0] = (adda[0] & addb[0]) | (adda[0] & reg_carry[0]) | (addb[0] & reg_carry[0]);
    assign result = reg_result[PIPELINE_STAGES-1];
    assign o_en = reg_i_en[2];
    // Always Block for reg_i_en
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            reg_i_en <= 3'b0;
        end else begin
            reg_i_en[2:1] <= reg_i_en[1:0];
            reg_i_en[0] <= reg_i_en[2];
        end
    end
    // Always Block for reg_adda
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            reg_adda[0] <= 64'b0;
        end else begin
            reg_adda[0] <= adda;
        end
    end
    // Always Block for reg_addb
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            reg_addb[0] <= 64'b0;
        end else begin
            reg_addb[0] <= addb;
        end
    end
    // Generate Block for Pipeline Stages
    genvar i;
    generate
        for (i = 0; i < PIPELINE_STAGES - 1; i = i + 1) begin : pipeline_stages
            // Always Block for reg_result
            always @(posedge clk or negedge rst_n) begin
                if (!rst_n) begin
                    reg_result[i] <= 65'b0;
                end else begin
                    reg_result[i] <= reg_result[i+1];
                end
            end
            // Always Block for reg_carry
            always @(posedge clk or negedge rst_n) begin
                if (!rst_n) begin
                    reg_carry[i] <= 65'b0;
                end else begin
                    reg_carry[i] <= reg_carry[i+1];
                end
            end
            // Wire Assignments
            assign sum[i+1] = reg_adda[i][i] ^ reg_addb[i][i] ^ reg_carry[i][i];
            assign carry[i+1] = (reg_adda[i][i] & reg_addb[i][i]) | (reg_adda[i][i] & reg_carry[i][i]) | (reg_addb[i][i] & reg_carry[i][i]);
            assign reg_result[i+1][i] = sum[i+1];
            assign reg_carry[i+1][i] = carry[i+1];
        end
    endgenerate
    // Always Block for reg_result
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            reg_result[PIPELINE_STAGES-1] <= 65'b0;
        end else begin
            reg_result[PIPELINE_STAGES-1][63:0] <= sum[63:0];
            reg_result[PIPELINE_STAGES-1][64] <= carry[63];
        end
    end
    // Always Block for reg_carry
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            reg_carry[PIPELINE_STAGES-1] <= 65'b0;
        end else begin
            reg_carry[PIPELINE_STAGES-1] <= carry[63:0];
        end
    end
    // ADD YOUR CODE ABOVE THIS LINE
endmodule
